arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_752c49fad3854a1a8aa1f42824f3a777.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @if (!submitted)
    {
        @switch (currentStep)
        {
            case 1:
                <StepPersonalInfo FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                  FullNameChanged="v => fullName = v"
                                  EmailChanged="v => email = v"
                                  PhoneChanged="v => phone = v"
                                  AddressChanged="v => address = v"
                                  ValidationErrors="validationErrors"
                                  OnNext="NextFromPersonalInfo" />
                break;
            case 2:
                <StepWorkHistory WorkEntries="workEntries"
                                 ValidationErrors="validationErrors"
                                 OnBack="Back"
                                 OnNext="NextFromWorkHistory" />
                break;
            case 3:
                <StepReferences References="references"
                                ValidationErrors="validationErrors"
                                OnBack="Back"
                                OnNext="NextFromReferences" />
                break;
            case 4:
                <StepCoverLetter @bind-CoverLetter="coverLetter"
                                 MaxLength="2000"
                                 ValidationErrors="validationErrors"
                                 OnBack="Back"
                                 OnNext="NextFromCoverLetter" />
                break;
            case 5:
                <StepReview FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                            WorkEntries="workEntries" References="references" CoverLetter="@coverLetter"
                            IsSubmitting="isSubmitting" SubmitError="@submitError"
                            OnEdit="GoToStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
    else
    {
        <div class="card border-success mt-4">
            <div class="card-body text-center py-5">
                <div class="text-success mb-3" style="font-size: 3rem;">&#10003;</div>
