@rendermode InteractiveServer
@using sv_752c49fad3854a1a8aa1f42824f3a777.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @if (!submitted)
    {
        @switch (currentStep)
        {
            case 1:
                <StepPersonalInfo FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                  FullNameChanged="v => fullName = v"
                                  EmailChanged="v => email = v"
                                  PhoneChanged="v => phone = v"
                                  AddressChanged="v => address = v"
                                  ValidationErrors="validationErrors"
                                  OnNext="NextFromPersonalInfo" />
                break;
            case 2:
                <StepWorkHistory WorkEntries="workEntries"
                                 ValidationErrors="validationErrors"
                                 OnBack="Back"
                                 OnNext="NextFromWorkHistory" />
                break;
            case 3:
                <StepReferences References="references"
                                ValidationErrors="validationErrors"
                                OnBack="Back"
                                OnNext="NextFromReferences" />
                break;
            case 4:
                <StepCoverLetter @bind-CoverLetter="coverLetter"
                                 MaxLength="2000"
                                 ValidationErrors="validationErrors"
                                 OnBack="Back"
                                 OnNext="NextFromCoverLetter" />
                break;
            case 5:
                <StepReview FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                            WorkEntries="workEntries" References="references" CoverLetter="@coverLetter"
                            IsSubmitting="isSubmitting" SubmitError="@submitError"
                            OnEdit="GoToStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
    else
    {
        <div class="card border-success mt-4">
            <div class="card-body text-center py-5">
                <div class="text-success mb-3" style="font-size: 3rem;">&#10003;</div>
                <h3 class="text-success">Application Submitted!</h3>
                <p class="text-muted mt-2">Your application has been received.</p>
                <p class="fs-5">Application ID: <strong>@applicationId</strong></p>
            </div>
        </div>
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();
    private Dictionary<string, string> validationErrors = new();
    private bool isSubmitting;
    private bool submitted;
    private int applicationId;
    private string? submitError;

    // Step 1
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };

    // Step 3
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step))
        {
            validationErrors.Clear();
            currentStep = step;
        }
    }

    private void Back()
    {
        validationErrors.Clear();
        currentStep--;
    }

    private async Task NextFromPersonalInfo()
    {
        validationErrors.Clear();

        if (string.IsNullOrWhiteSpace(fullName))
            validationErrors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(email))
            validationErrors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(phone))
            validationErrors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(address))
            validationErrors["Address"] = "Address is required.";

        if (validationErrors.Count > 0) return;

        var emailValid = await ApplicationService.ValidateEmailAsync(email);
        if (!emailValid)
        {
            validationErrors["Email"] = "Please enter a valid email address.";
            return;
        }

        completedSteps.Add(1);
        currentStep = 2;
    }

    private void NextFromWorkHistory()
    {
        validationErrors.Clear();

        for (int i = 0; i < workEntries.Count; i++)
        {
            var e = workEntries[i];
            if (string.IsNullOrWhiteSpace(e.Company))
                validationErrors[$"Work[{i}].Company"] = $"Company is required for position {i + 1}.";
            if (string.IsNullOrWhiteSpace(e.Title))
                validationErrors[$"Work[{i}].Title"] = $"Job title is required for position {i + 1}.";
            if (e.StartDate == default)
                validationErrors[$"Work[{i}].StartDate"] = $"Start date is required for position {i + 1}.";
        }

        if (validationErrors.Count > 0) return;

        completedSteps.Add(2);
        currentStep = 3;
    }

    private void NextFromReferences()
    {
        validationErrors.Clear();

        for (int i = 0; i < references.Count; i++)
        {
            var r = references[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                validationErrors[$"Ref[{i}].Name"] = $"Name is required for reference {i + 1}.";
            if (string.IsNullOrWhiteSpace(r.Relationship))
                validationErrors[$"Ref[{i}].Relationship"] = $"Relationship is required for reference {i + 1}.";
            if (string.IsNullOrWhiteSpace(r.Email))
                validationErrors[$"Ref[{i}].Email"] = $"Email is required for reference {i + 1}.";
            if (string.IsNullOrWhiteSpace(r.Phone))
                validationErrors[$"Ref[{i}].Phone"] = $"Phone is required for reference {i + 1}.";
        }

        if (validationErrors.Count > 0) return;

        completedSteps.Add(3);
        currentStep = 4;
    }

    private void NextFromCoverLetter()
    {
        validationErrors.Clear();

        if (string.IsNullOrWhiteSpace(coverLetter))
        {
            validationErrors["CoverLetter"] = "Cover letter is required.";
            return;
        }

        completedSteps.Add(4);
        currentStep = 5;
    }

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        submitError = null;
        StateHasChanged();

        try
        {
            var personal = new PersonalInfo(fullName, email, phone, address);
            var work = new WorkHistory(workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var refs = references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, work, refs, coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            completedSteps.Add(5);
            submitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}
