@{
    var stepNames = new[] { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
}

<div class="d-flex align-items-center justify-content-between mb-4 flex-wrap gap-1">
    @for (int i = 0; i < stepNames.Length; i++)
    {
        var step = i + 1;
        var isCompleted = CompletedSteps.Contains(step);
        var isCurrent = step == CurrentStep;
        var isClickable = isCompleted && !isCurrent;

        <div class="d-flex align-items-center">
            <button class="btn btn-sm rounded-pill px-3 py-1 @(isCurrent ? "btn-primary" : isCompleted ? "btn-outline-success" : "btn-outline-secondary") @(!isClickable ? "" : "cursor-pointer")"
                    disabled="@(!isClickable)"
                    @onclick="() => OnStepClicked.InvokeAsync(step)">
                @if (isCompleted && !isCurrent)
                {
                    <span class="me-1">&#10003;</span>
                }
                <span>@stepNames[i]</span>
            </button>

            @if (step < stepNames.Length)
            {
                <span class="mx-1 text-muted">&rarr;</span>
            }
        </div>
    }
</div>

