toolArgs.file_text:
@using static sv_752c49fad3854a1a8aa1f42824f3a777.Components.Pages.Apply.Apply

<div class="card mt-3">
    <div class="card-body">
        <h4 class="card-title">Work History</h4>

        @for (int idx = 0; idx < WorkEntries.Count; idx++)
        {
            var i = idx;
            var entry = WorkEntries[i];

            <div class="border rounded p-3 mb-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="mb-0">Position @(i + 1)</h6>
                    @if (WorkEntries.Count > 1)
                    {
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(i)">Remove</button>
                    }
                </div>

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Company <span class="text-danger">*</span></label>
                        <input class="form-control @(ValidationErrors.ContainsKey($"Work[{i}].Company") ? "is-invalid" : "")"
                               value="@entry.Company" @oninput="e => entry.Company = e.Value?.ToString() ?? """/>
                        @if (ValidationErrors.TryGetValue($"Work[{i}].Company", out var cErr))
                        {
                            <div class="invalid-feedback">@cErr</div>
                        }
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
                        <input class="form-control @(ValidationErrors.ContainsKey($"Work[{i}].Title") ? "is-invalid" : "")"
                               value="@entry.Title" @oninput="e => entry.Title = e.Value?.ToString() ?? """/>
                        @if (ValidationErrors.TryGetValue($"Work[{i}].Title", out var tErr))
                        {
                            <div class="invalid-feedback">@tErr</div>
                        }
                    </div>
                </div>

                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
                        <input type="date" class="form-control @(ValidationErrors.ContainsKey($"Work[{i}].StartDate") ? "is-invalid" : "")"
                               value="@(entry.StartDate == default ? "" : entry.StartDate.ToString("yyyy-MM-dd"))"
                               @onchange="e => entry.StartDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : default" />
                        @if (ValidationErrors.TryGetValue($"Work[{i}].StartDate", out var sErr))
                        {
                            <div class="invalid-feedback">@sErr</div>
                        }
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" disabled="@entry.IsCurrent"
                               value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                               @onchange="e => entry.EndDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null" />
                    </div>
                    <div class="col-md-4 d-flex align-items-end mb-1">
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" checked="@entry.IsCurrent"
                                   @onchange="e => { entry.IsCurrent = (bool)(e.Value ?? false); if (entry.IsCurrent) entry.EndDate = null; }" />
                            <label class="form-check-label">Currently working here</label>
                        </div>
                    </div>
                </div>

                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="2" @oninput="e => entry.Description = e.Value?.ToString() ?? """>@entry.Description</textarea>
                </div>
            </div>
        }

        <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">+ Add Another Position</button>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">&larr; Back</button>
            <button class="btn btn-primary" @onclick="OnNext">Next &rarr;</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public Dictionary<string, string> ValidationErrors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry() => WorkEntries.Add(new WorkEntryModel());
    private void RemoveEntry(int index) => WorkEntries.RemoveAt(index);
}

@using static sv_752c49fad3854a1a8aa1f42824f3a777.Components.Pages.Apply.Apply

<div class="card mt-3">
    <div class="card-body">
        <h4 class="card-title">References</h4>

        @for (int idx = 0; idx < References.Count; idx++)
