toolArgs.old_str:
@using static sv_752c49fad3854a1a8aa1f42824f3a777.Components.Pages.Apply.Apply

<div class="card mt-3">
    <div class="card-body">
        <h4 class="card-title">References</h4>

        @for (int idx = 0; idx < References.Count; idx++)
        {
            var i = idx;
            var r = References[i];

            <div class="border rounded p-3 mb-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="mb-0">Reference @(i + 1)</h6>
                    @if (References.Count > 2)
                    {
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(i)">Remove</button>
                    }
                </div>

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Name <span class="text-danger">*</span></label>
                        <input class="form-control @(ValidationErrors.ContainsKey($"Ref[{i}].Name") ? "is-invalid" : "")"
                               value="@r.Name" @oninput="e => r.Name = e.Value?.ToString() ?? """/>
                        @if (ValidationErrors.TryGetValue($"Ref[{i}].Name", out var nErr))
                        {
                            <div class="invalid-feedback">@nErr</div>
                        }
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Relationship <span class="text-danger">*</span></label>
                        <input class="form-control @(ValidationErrors.ContainsKey($"Ref[{i}].Relationship") ? "is-invalid" : "")"
                               value="@r.Relationship" @oninput="e => r.Relationship = e.Value?.ToString() ?? """/>
                        @if (ValidationErrors.TryGetValue($"Ref[{i}].Relationship", out var rErr))
                        {
                            <div class="invalid-feedback">@rErr</div>
                        }
                    </div>
                </div>

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control @(ValidationErrors.ContainsKey($"Ref[{i}].Email") ? "is-invalid" : "")"
                               value="@r.Email" @oninput="e => r.Email = e.Value?.ToString() ?? """/>
                        @if (ValidationErrors.TryGetValue($"Ref[{i}].Email", out var eErr))
                        {
                            <div class="invalid-feedback">@eErr</div>
                        }
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Phone <span class="text-danger">*</span></label>
                        <input type="tel" class="form-control @(ValidationErrors.ContainsKey($"Ref[{i}].Phone") ? "is-invalid" : "")"
                               value="@r.Phone" @oninput="e => r.Phone = e.Value?.ToString() ?? """/>
                        @if (ValidationErrors.TryGetValue($"Ref[{i}].Phone", out var pErr))
                        {
                            <div class="invalid-feedback">@pErr</div>
                        }
                    </div>
                </div>
            </div>
        }

        @if (References.Count < 3)
        {
            <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddReference">+ Add Reference</button>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">&larr; Back</button>
            <button class="btn btn-primary" @onclick="OnNext">Next &rarr;</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public Dictionary<string, string> ValidationErrors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddReference() { if (References.Count < 3) References.Add(new ReferenceModel()); }
    private void RemoveReference(int index) { if (References.Count > 2) References.RemoveAt(index); }
}

